type OFTV2ConstructorParams =
  | [signer?: Signer]
  | ConstructorParameters<typeof ContractFactory>;

const isSuperArgs = (
  xs: OFTV2ConstructorParams
): xs is ConstructorParameters<typeof ContractFactory> => xs.length > 1;

export class OFTV2__factory extends ContractFactory {
  constructor(...args: OFTV2ConstructorParams) {
    if (isSuperArgs(args)) {
      super(...args);
    } else {
      super(_abi, _bytecode, args[0]);
    }
  }

  override deploy(
    _name: string,
    _symbol: string,
    _sharedDecimals: BigNumberish,
    _lzEndpoint: string,
    overrides?: Overrides & { from?: string }
  ): Promise<OFTV2> {
    return super.deploy(
      _name,
      _symbol,
      _sharedDecimals,
      _lzEndpoint,
      overrides || {}
    ) as Promise<OFTV2>;
  }
  override getDeployTransaction(
    _name: string,
    _symbol: string,
    _sharedDecimals: BigNumberish,
    _lzEndpoint: string,
    overrides?: Overrides & { from?: string }
  ): TransactionRequest {
    return super.getDeployTransaction(
      _name,
      _symbol,
      _sharedDecimals,
      _lzEndpoint,
      overrides || {}
    );
  }
  override attach(address: string): OFTV2 {
    return super.attach(address) as OFTV2;
  }
  override connect(signer: Signer): OFTV2__factory {
    return super.connect(signer) as OFTV2__factory;
  }

  static readonly bytecode = _bytecode;
  static readonly abi = _abi;
  static createInterface(): OFTV2Interface {
    return new utils.Interface(_abi) as OFTV2Interface;
  }
  static connect(address: string, signerOrProvider: Signer | Provider): OFTV2 {
    return new Contract(address, _abi, signerOrProvider) as OFTV2;
  }
}
